SELECT ps.* FROM product_snapshot ps LEFT JOIN product_operation_state pos ON ps.activity_id = pos.activity_id AND ps.product_id = pos.product_id AND pos.deleted = 0 WHERE ps.activity_id = #{activityId} AND ps.deleted = 0
AND ps.status = #{promotionStatus}
AND ps.status IN (0, 1, 2, 3, 4, 6)
AND ( ps.title LIKE CONCAT('%', #{productInfo}, '%') OR ps.product_id LIKE CONCAT('%', #{productInfo}, '%') OR ps.shop_name LIKE CONCAT('%', #{productInfo}, '%') )
AND ps.product_id IN
#{id}
AND ( ps.product_id IN
#{id}
OR ps.product_id NOT IN
#{id}
)
AND ps.product_id IN
#{id}
AND ps.product_id NOT IN
#{id}
AND ps.product_id IN
#{id}
ORDER BY CASE WHEN pos.pinned_until IS NOT NULL AND pos.pinned_until > #{now} AND pos.deleted = 0 THEN 0 ELSE 1 END ASC, CASE WHEN (pos.promote_link IS NOT NULL AND TRIM(pos.promote_link) <> '') OR (pos.short_link IS NOT NULL AND TRIM(pos.short_link) <> '') THEN 0 ELSE 1 END ASC, ps.activity_cos_ratio DESC NULLS LAST, ps.sync_time DESC NULLS LAST LIMIT #{limit} OFFSET #{offset}

SELECT ps.*
  FROM product_snapshot ps
  JOIN product_operation_state pos
    ON ps.activity_id = pos.activity_id
   AND ps.product_id = pos.product_id


   AND (
        CASE
          WHEN pos.pinned_until IS NOT NULL AND pos.pinned_until > #{snapshotTime}
          THEN 0 ELSE 1
        END > #{cursorPinnedRank}
        OR (
            CASE
              WHEN pos.pinned_until IS NOT NULL AND pos.pinned_until > #{snapshotTime}
              THEN 0 ELSE 1
            END = #{cursorPinnedRank}
            AND COALESCE(, TIMESTAMP '0001-01-01 00:00:00') < #{cursorPromotionStartTime}
        )
        OR (
            CASE
              WHEN pos.pinned_until IS NOT NULL AND pos.pinned_until > #{snapshotTime}
              THEN 0 ELSE 1
            END = #{cursorPinnedRank}
            AND COALESCE(, TIMESTAMP '0001-01-01 00:00:00') = #{cursorPromotionStartTime}
            AND COALESCE(ps.sync_time, TIMESTAMP '0001-01-01 00:00:00') < #{cursorSyncTime}
        )
        OR (
            CASE
              WHEN pos.pinned_until IS NOT NULL AND pos.pinned_until > #{snapshotTime}
              THEN 0 ELSE 1
            END = #{cursorPinnedRank}
            AND COALESCE(, TIMESTAMP '0001-01-01 00:00:00') = #{cursorPromotionStartTime}
            AND COALESCE(ps.sync_time, TIMESTAMP '0001-01-01 00:00:00') = #{cursorSyncTime}
            AND COALESCE(pos.selected_at, TIMESTAMP '0001-01-01 00:00:00') < #{cursorSelectedAt}
        )
        OR (
            CASE
              WHEN pos.pinned_until IS NOT NULL AND pos.pinned_until > #{snapshotTime}
              THEN 0 ELSE 1
            END = #{cursorPinnedRank}
            AND COALESCE(, TIMESTAMP '0001-01-01 00:00:00') = #{cursorPromotionStartTime}
            AND COALESCE(ps.sync_time, TIMESTAMP '0001-01-01 00:00:00') = #{cursorSyncTime}
            AND COALESCE(pos.selected_at, TIMESTAMP '0001-01-01 00:00:00') = #{cursorSelectedAt}
            AND ps.activity_id > #{cursorActivityId}
        )
        OR (
            CASE
              WHEN pos.pinned_until IS NOT NULL AND pos.pinned_until > #{snapshotTime}
              THEN 0 ELSE 1
            END = #{cursorPinnedRank}
            AND COALESCE(, TIMESTAMP '0001-01-01 00:00:00') = #{cursorPromotionStartTime}
            AND COALESCE(ps.sync_time, TIMESTAMP '0001-01-01 00:00:00') = #{cursorSyncTime}
            AND COALESCE(pos.selected_at, TIMESTAMP '0001-01-01 00:00:00') = #{cursorSelectedAt}
            AND ps.activity_id = #{cursorActivityId}
            AND ps.product_id > #{cursorProductId}
        )
   )

 ORDER BY
        CASE
          WHEN pos.pinned_until IS NOT NULL AND pos.pinned_until > #{snapshotTime}
          THEN 0 ELSE 1
        END ASC,
        COALESCE(, TIMESTAMP '0001-01-01 00:00:00') DESC,
        COALESCE(ps.sync_time, TIMESTAMP '0001-01-01 00:00:00') DESC,
        COALESCE(pos.selected_at, TIMESTAMP '0001-01-01 00:00:00') DESC,
        ps.activity_id ASC,
        ps.product_id ASC
 LIMIT #{limit}
